 21→            const colorHex = chainColors?.get(link.id) || STAR_COLORS[i % STAR_COLORS.length];
 22→            const rgb = parseHex(colorHex);
 23→            const isPending = link.status === 'pending';
 24→            const isDeclined = link.status === 'declined';
 25→            const isOwnPending = isPending && (link.user_id_a === userId || link.user_id_b === userId);
